// monta o e-mail pro Arthur a partir do payload do formulario
const b = $input.first().json.body || $input.first().json;
const nome = (b.nome || '(sem nome)').toString().trim();
const whats = (b.whatsapp || b.whatsappNormalizado || '(não informado)').toString();
const norm = (b.whatsappNormalizado || '').toString().replace(/\D/g, '');
const email = (b.email || '(não informado)').toString();
const msg = (b.mensagem || '(sem mensagem)').toString().trim();
const temProjeto = b.temProjeto ? 'Sim' : 'Não';
let quando = '';
try { quando = b.timestamp ? new Date(b.timestamp).toLocaleString('pt-BR', { timeZone: 'America/Sao_Paulo' }) : ''; } catch (e) {}

// link wa.me para o Arthur abrir conversa com o lead (mensagem já preenchida)
const textoWpp = `Olá ${nome}, tudo bem? Vi que você enviou seu contato no formulário do nosso site. Estou entrando em contato para entender como posso te ajudar: qual é a sua ideia, se você já tem um projeto ou não. Fico à disposição!`;
const linkWpp = norm ? `https://wa.me/${norm}?text=${encodeURIComponent(textoWpp)}` : (b.whatsappLinkLead || '');

const subject = `Novo lead do site Movelart: ${nome}`;
const html = `<!DOCTYPE html><html lang="pt-BR"><head><meta charset="UTF-8"></head><body>
<div style="font-family:Arial,sans-serif;max-width:560px;color:#0D1B2A">
  <div style="background:#0D1B2A;padding:20px 28px;border-radius:8px 8px 0 0">
    <h2 style="margin:0;color:#ffffff;font-size:18px">Novo lead pelo site da Movelart</h2>
    <p style="margin:4px 0 0;color:#ffffff99;font-size:12px">moveismovelart.com.br &middot; ${quando}</p>
  </div>
  <div style="border:1px solid #E5E5E4;border-top:none;padding:24px 28px;border-radius:0 0 8px 8px">
    <table style="border-collapse:collapse;width:100%">
      <tr><td style="padding:6px 0;width:130px;color:#6B6854;font-size:12px;text-transform:uppercase;letter-spacing:1px">Nome</td><td style="padding:6px 0;font-size:15px">${nome}</td></tr>
      <tr><td style="padding:6px 0;color:#6B6854;font-size:12px;text-transform:uppercase;letter-spacing:1px">WhatsApp</td><td style="padding:6px 0;font-size:15px">${whats}</td></tr>
      <tr><td style="padding:6px 0;color:#6B6854;font-size:12px;text-transform:uppercase;letter-spacing:1px">E-mail</td><td style="padding:6px 0;font-size:15px">${email}</td></tr>
      <tr><td style="padding:6px 0;color:#6B6854;font-size:12px;text-transform:uppercase;letter-spacing:1px">Tem projeto</td><td style="padding:6px 0;font-size:15px">${temProjeto}</td></tr>
      <tr><td style="padding:6px 0;color:#6B6854;font-size:12px;text-transform:uppercase;letter-spacing:1px;vertical-align:top">Mensagem</td><td style="padding:6px 0;font-size:15px">${msg}</td></tr>
    </table>
    <div style="margin-top:24px">
      <a href="${linkWpp}" style="background:#25D366;color:#ffffff;padding:14px 24px;border-radius:8px;text-decoration:none;font-weight:bold;font-size:15px;display:inline-block">💬 Responder no WhatsApp</a>
    </div>
    <p style="margin-top:24px;font-size:11px;color:#6B6854">Aviso automático do site da Movelart. Link direto: ${linkWpp}</p>
  </div>
</div>
</body></html>`;

return [{ json: { subject, html, nome, email } }];
